import React, { useState } from 'react';
import styled from 'styled-components';
import { motion, AnimatePresence } from 'framer-motion';

const ChatbotContainer = styled.div`
  position: fixed;
  bottom: 20px;
  right: 20px;
  z-index: 1000;
`;

const ChatbotToggle = styled(motion.button)`
  width: 55px;
  height: 55px;
  border-radius: 50%;
  background: ${props => props.theme.colors.accentPrimary};
  border: none;
  color: #000;
  font-size: 1.4rem;
  cursor: pointer;
  box-shadow: ${props => props.theme.shadows.glow};
  display: flex;
  align-items: center;
  justify-content: center;
  transition: ${props => props.theme.transitions.default};

  &:hover {
    transform: scale(1.1) rotate(5deg);
  }
`;

const ChatWindow = styled(motion.div)`
  position: absolute;
  bottom: 70px;
  right: 0;
  width: 400px;
  height: 600px;
  background: rgba(10, 10, 10, 0.8);
  border-radius: 40px;
  box-shadow: 0 50px 100px rgba(0, 0, 0, 0.5);
  display: flex;
  flex-direction: column;
  border: 1px solid rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(40px);
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    inset: 0;
    background: radial-gradient(circle at 0% 0%, rgba(0, 242, 254, 0.05) 0%, transparent 50%);
    pointer-events: none;
  }
`;

const ChatHeader = styled.div`
  padding: 2rem;
  background: rgba(255, 255, 255, 0.02);
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
`;

const ChatTitle = styled.h3`
  margin: 0;
  font-size: 0.9rem;
  font-weight: 900;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: #fff;
  display: flex;
  align-items: center;
  gap: 0.8rem;

  &::before {
    content: '';
    width: 8px;
    height: 8px;
    background: #00ffa3;
    border-radius: 50%;
    box-shadow: 0 0 10px #00ffa3;
  }
`;

const MessageList = styled.div`
  flex: 1;
  overflow-y: auto;
  padding: 2rem;
  display: flex;
  flex-direction: column;
  gap: 1.5rem;

  &::-webkit-scrollbar {
    width: 4px;
  }

  &::-webkit-scrollbar-track {
    background: transparent;
  }

  &::-webkit-scrollbar-thumb {
    background: rgba(255, 255, 255, 0.1);
    border-radius: 10px;
  }
`;

const Message = styled(motion.div)<{ isBot: boolean }>`
  display: flex;
  justify-content: ${props => props.isBot ? 'flex-start' : 'flex-end'};
`;

const MessageBubble = styled.div<{ isBot: boolean }>`
  max-width: 85%;
  padding: 1rem 1.4rem;
  border-radius: ${props => props.isBot ? '24px 24px 24px 4px' : '24px 24px 4px 24px'};
  background: ${props => props.isBot ? 'rgba(255, 255, 255, 0.03)' : 'linear-gradient(135deg, #00f2fe 0%, #4facfe 100%)'};
  color: ${props => props.isBot ? 'rgba(255, 255, 255, 0.8)' : '#000'};
  font-size: 0.9rem;
  line-height: 1.6;
  font-weight: 500;
  border: 1px solid ${props => props.isBot ? 'rgba(255, 255, 255, 0.05)' : 'transparent'};
  box-shadow: ${props => !props.isBot ? '0 10px 20px rgba(0, 242, 254, 0.2)' : 'none'};
`;

const InputContainer = styled.form`
  padding: 1.5rem 2rem;
  background: rgba(255, 255, 255, 0.01);
  display: flex;
  gap: 1rem;
  border-top: 1px solid rgba(255, 255, 255, 0.05);
`;

const Input = styled.input`
  flex: 1;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 20px;
