const Chatbot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      text: 'SYSTEM INITIALIZED. NEURAL UPLINK ESTABLISHED. тЪб\n\nI am Zeus Core Assistant. Ready to provide strategic financial intelligence and portfolio diagnostics.',
      isBot: true,
      timestamp: new Date()
    }
  ]);
  const [inputValue, setInputValue] = useState('');

  const findResponse = (userMessage: string): string => {
    const words = userMessage.toLowerCase().trim().split(/\s+/);
    let bestMatch = null;
    let highestScore = 0;

    for (const faq of FAQs) {
      let score = 0;
      for (const keyword of faq.keywords) {
        if (userMessage.toLowerCase().includes(keyword)) {
          score += 2; // Exact keyword match
        }
        for (const word of words) {
          if (word === keyword) score += 3; // Word-for-word match
        }
      }

      if (score > highestScore) {
        highestScore = score;
        bestMatch = faq;
      }
    }

    if (highestScore > 1) {
      return bestMatch!.response;
    }

    return "I'm still learning about that! ЁЯза Try asking about:\nтАв Gold/Silver prices\nтАв P/E Ratio or RSI\nтАв Portfolio management\nтАв Market predictions\nтАв App features like API keys";
  };

  const handleSendMessage = () => {
    if (!inputValue.trim()) return;

    const userMsgText = inputValue;
    const userMessage: ChatMessage = {
      id: Date.now().toString(),
      text: userMsgText,
      isBot: false,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsTyping(true);

    // Simulate bot thinking/typing
    setTimeout(() => {
      const response = findResponse(userMsgText);
      const botMessage: ChatMessage = {
        id: (Date.now() + 1).toString(),
        text: response,
        isBot: true,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMessage]);
      setIsTyping(false);
    }, 1200);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleSendMessage();
  };

  return (
    <ChatbotContainer>
      <ChatbotToggle
        onClick={() => setIsOpen(!isOpen)}
        animate={{ scale: isOpen ? 0.9 : 1 }}
        title="Chat Assistant"
      >
        {isOpen ? 'тЬХ' : 'ЁЯТм'}
      </ChatbotToggle>

      <AnimatePresence mode="wait">
        {isOpen && (
          <ChatWindow
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            transition={{ type: 'spring', damping: 25, stiffness: 300 }}
          >
            <ChatHeader>
              <ChatTitle>Assistant</ChatTitle>
              <div style={{ opacity: 0.6, fontSize: '0.8rem' }}>Online</div>
            </ChatHeader>

            <MessageList>
              {messages.map((message) => (
                <Message
                  key={message.id}
                  isBot={message.isBot}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                >
                  <MessageBubble isBot={message.isBot}>
                    {message.text.split('\n').map((line, i) => (
                      <div key={i}>{line}</div>
                    ))}
                  </MessageBubble>
                </Message>
              ))}
              {isTyping && (
                <Message isBot={true} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
                  <TypingIndicator>
                    <span></span>
                    <span></span>
                    <span></span>
                  </TypingIndicator>
                </Message>
              )}
            </MessageList>

            <InputContainer onSubmit={handleSubmit}>
              <Input
                type="text"
                placeholder="Type a message..."
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
              />
              <SendButton type="submit" disabled={!inputValue.trim()}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <line x1="22" y1="2" x2="11" y2="13"></line>
                  <polygon points="22 2 15 22 11 13 2 9 22 2"></polygon>
                </svg>
              </SendButton>
            </InputContainer>
          </ChatWindow>
        )}
      </AnimatePresence>
    </ChatbotContainer>
  );
};

export default Chatbot;
